pragma solidity ^0.8.9;

import { ERC721Base } from "@solidstate/contracts/token/ERC721/base/ERC721Base.sol";
import { ERC1155Base } from "@solidstate/contracts/token/ERC1155/base/ERC1155Base.sol";
import { EnumerableSet } from "@solidstate/contracts/data/EnumerableSet.sol";

import "../../SilksMarketplaceStorage.sol";

// Struct for a marketplace listing type.
    struct ListingType {
        address contractAddress;
        string description;
        uint256 ercStandard;
        bool active;
        bool valid;
    }

// Struct for a marketplace listing.
    struct Listing {
        bytes32 listingId;       // Unique identifier for the listing.
        address listingAddress;  // Address for listing's contract.
        address seller;          // Address of the seller.
        address buyer;           // Address of the buyer.
        uint256 tokenId;         // Token ID associated with the listing.
        uint256 numListed;        // Quantity Of token listed
        uint256 pricePer;        // Price per token of the listing.
        uint256 royaltyBasePoints;      // Royalty percentage.
        bool active;             // Status of the listing (active/inactive).
        bool valid;              // Validity of the listing.
    }

bytes32 constant LISTING_ADMIN_ROLE = keccak256("silks.contracts.roles.ListingAdminRole");
bytes32 constant LISTINGS_PAUSED = keccak256('silks.contracts.paused.Listings');

    error InvalidListing(bytes32 listingId);
    error ListingAlreadyPurchased(bytes32 listingId);
    error InvalidListingType(address listingAddress);
    error InactiveListingType(address listingAddress);
    error UnsupportedERCStandard(uint256 ercStandard);
    error CreateListingFailed(string reason, bytes32 listingId, address listingAddress, address seller, address buyer, uint256 tokenId, uint256 numListed, uint256 pricePer, uint256 royaltyBasePoints, bool active);

library ListingStorage {
    using EnumerableSet for EnumerableSet.UintSet;
    using EnumerableSet for EnumerableSet.Bytes32Set;

    // Storage slot for the layout.
    bytes32 internal constant STORAGE_SLOT = keccak256('silks.contracts.storage.SilksMarketplaceListings');

    // Struct for the layout of the marketplace.
    struct Layout {
        mapping(address => ListingType) listingTypes;

        mapping(bytes32 => Listing) listings;
        mapping(address => EnumerableSet.Bytes32Set) purchasesByAddress;
        mapping(address => EnumerableSet.UintSet) tokensListedByListingAddress;
        EnumerableSet.Bytes32Set activeListings;
        EnumerableSet.UintSet supportedERCStandards;
    }

    // Function to retrieve the layout.
    function layout()
    internal
    pure
    returns (
        Layout storage _l
    ) {
        bytes32 slot = STORAGE_SLOT;
        assembly {
            _l.slot := slot
        }
    }

    /**
     * @dev Internal function to verify if an asset can be sold.
     * @param _listingAddress Contract address for the listing.
     * @param _addressToCheck The address to check for ownership and approval.
     * @param _tokenId The token ID of the asset.
     */
    function verifyAssetCanBeSold(
        address _listingAddress,
        address _addressToCheck,
        uint256 _tokenId,
        uint256 _quantity
    )
    internal
    view
    {
        // Access marketplace layout
        ListingType storage listingType = layout().listingTypes[_listingAddress];

        // Validate listing type and address
        if (!listingType.valid) {
            revert InvalidListingType(_listingAddress);
        }

        // Validate token ownership and approval
        if (listingType.ercStandard == 721){
            ERC721Base assetContract = ERC721Base(listingType.contractAddress);
            if (assetContract.ownerOf(_tokenId) != _addressToCheck) {
                revert NotTokenOwner(_listingAddress, _addressToCheck, _tokenId);
            }
            if (!assetContract.isApprovedForAll(_addressToCheck, address(this))) {
                revert ApprovalNotSetForMarketplace();
            }
        } else if (listingType.ercStandard == 1155){
            ERC1155Base assetContract = ERC1155Base(listingType.contractAddress);
            uint256 numOwned = assetContract.balanceOf(_addressToCheck, _tokenId);
            if (numOwned == 0){
                revert NotTokenOwner(_listingAddress, msg.sender, _tokenId);
            }
            if (_quantity > numOwned){
                revert InvalidIntValue("INV_QTY", _quantity, numOwned);
            }
            if (!assetContract.isApprovedForAll(_addressToCheck, address(this))) {
                revert ApprovalNotSetForMarketplace();
            }
        } else {
            revert("UNSUPPORTED_ERC_STANDARD");
        }
    }

    /**
     * @dev Internal function to create a listing.
     * @param _listing The listing structure containing listing details.
     */
    function createListing(
        Listing memory _listing
    )
    internal
    {
        // Verify asset can be sold
        verifyAssetCanBeSold(_listing.listingAddress, _listing.seller, _listing.tokenId, _listing.numListed);

        // Validate price is not zero
        if (_listing.pricePer == 0) {
            revert CreateListingFailed("INV_PRICE", _listing.listingId, _listing.listingAddress, _listing.seller, _listing.buyer, _listing.tokenId, _listing.numListed, _listing.pricePer, _listing.royaltyBasePoints, _listing.active);
        }

        // Access marketplace layout and check if token is already listed
        ListingType storage listingType = layout().listingTypes[_listing.listingAddress];
        if (!listingType.active){
            revert InactiveListingType(_listing.listingAddress);
        }

        EnumerableSet.UintSet storage supportedERCStandards = layout().supportedERCStandards;
        if (!supportedERCStandards.contains(listingType.ercStandard)){
            revert UnsupportedERCStandard(listingType.ercStandard);
        }

        EnumerableSet.UintSet storage tokensListedForListingAddress = layout().tokensListedByListingAddress[_listing.listingAddress];
        if (tokensListedForListingAddress.contains(_listing.tokenId)){
            revert CreateListingFailed("TOKEN_ALREADY_LISTED", _listing.listingId, _listing.listingAddress, _listing.seller, _listing.buyer, _listing.tokenId, _listing.numListed, _listing.pricePer, _listing.royaltyBasePoints, _listing.active);
        }

        // Add token to the listing and emit event
        tokensListedForListingAddress.add(_listing.tokenId);
        layout().listings[_listing.listingId] = Listing(
            _listing.listingId,
            _listing.listingAddress,
            _listing.seller,
            _listing.buyer,
            _listing.tokenId,
            _listing.numListed,
            _listing.pricePer,
            _listing.royaltyBasePoints,
            _listing.active,
            true
        );
        layout().activeListings.add(_listing.listingId);
    }

    function updateListing(
        Listing memory _listing
    )
    internal
    {
        Listing storage storedListing = layout().listings[_listing.listingId];

        if (!storedListing.valid){
            revert InvalidListing(_listing.listingId);
        }

        layout().listings[_listing.listingId] = _listing;
    }

    function transferTokens(
        address _contractAddress,
        address _from,
        address _to,
        uint256 _tokenId,
        uint256 _quantity
    )
    internal
    {
        // Transfer the token to the buyer
        ListingType storage listingType = layout().listingTypes[_contractAddress];
        if (listingType.ercStandard == 721){
            ERC721Base assetContract = ERC721Base(listingType.contractAddress);
            assetContract.safeTransferFrom(_from, _to, _tokenId);
        } else if (listingType.ercStandard == 1155){
            ERC1155Base assetContract = ERC1155Base(listingType.contractAddress);
            assetContract.safeTransferFrom(_from, _to, _tokenId, _quantity, "");
        } else {
            revert("UNSUPPORTED_ERC_STANDARD");
        }
    }
}","keccak256":"0x24060f610124f05889a759ab23654575e2794b197dd2d2c5e2bd2fe6eba70a9b","license":"UNLICENSED"},"contracts/facets/minting/SilksMinterStorage.sol":{"content":"// SPDX-License-Identifier: UNLICENSED
pragma solidity ^0.8.18;

import {AggregatorV3Interface} from "@chainlink/contracts/src/v0.8/interfaces/AggregatorV3Interface.sol";

import {EnumerableSet} from "@solidstate/contracts/data/EnumerableSet.sol";
import {ContractType} from "../../utils/constants.sol";

library SilksMinterStorage {
    using SilksMinterStorage for Layout;
    using EnumerableSet for EnumerableSet.AddressSet;
    using EnumerableSet for EnumerableSet.UintSet;

    bytes32 internal constant STORAGE_SLOT =
        keccak256("silks.contracts.storage.Minter");

    // Custom errors for specific revert scenarios
    error ContractIdentifierDoesNotExist(address _contractAddress);
    error ContractAlreadyExists(address _contractAddress);
    error InvalidOverlapInDiscounts(uint256 _seasonId, uint256 _discountId);
    error IdentifierNotFound(address _contractAddress);
    error DuplicatePayTier(uint256 _tier);

    struct Discount {
        uint256 discount; // Percentage for discount
        uint256 discountExpiration; // Unix timestamp for discount expiration
        uint256 discountStartDate; // Unix timestamp for discount start date
        EnumerableSet.UintSet usedAvatarTokens; // Set of avatar tokens that have used the discount
        uint256 avatarStartId; // Start of avatar token range
        uint256 avatarEndId; // End of avatar token range
    }

    struct ContractData {
        address contractAddress; // Address of the contract
        string mintFunctionSignature; // Signature of the mint function
        ContractType contractType; // Type of contract
        bool isPriceUSD; // Boolean to check if price is in USD
        mapping(uint256 => uint256) tierToPrice; // Mapping of tier to price
        EnumerableSet.UintSet tiers; // Set of tiers
    }

    struct Layout {
        mapping(uint256 => Discount[]) seasonIdToDiscounts; // Mapping of seasonId to discounts
        mapping(address => ContractData) contractsData; // Mapping of contract address to contract data
        EnumerableSet.AddressSet addresses; // Set of contract addresses
        address avatarAddress; // Address of the avatar contract
        bool mintingExclusiveToAvatarHolders; // Boolean to check if minting is exclusive to avatar holders
        uint256 mintingExclusionStartDateTime; // Unix timestamp for minting exclusion start date
        uint256 mintingExclusionEndDateTime; // Unix timestamp for minting exclusion end date
        address priceFeedAddress; // Address of the price feed for ETH/USD conversion
    }

    struct AddPayTier {
        uint256 tier;
        uint256 price;
    }

    function layout() internal pure returns (Layout storage l) {
        bytes32 slot = STORAGE_SLOT;
        assembly {
            l.slot := slot
        }
    }

    function removeContractData(
        Layout storage l,
        address contractAddress
    ) internal {
        if (l.contractsData[contractAddress].contractAddress == address(0))
            revert ContractIdentifierDoesNotExist(contractAddress);
        delete l.contractsData[contractAddress];
        l.addresses.remove(contractAddress);
    }

    function contains(
        Layout storage l,
        address contractAddress
    ) internal view returns (bool) {
        return l.addresses.contains(contractAddress);
    }

    function addContract(
        Layout storage l,
        address contractAddress,
        string memory mintFunctionSignature,
        ContractType contractType,
        bool isPriceUSD,
        AddPayTier[] memory payTiers
    ) internal {
        if (l.contractsData[contractAddress].contractAddress != address(0))
            revert ContractAlreadyExists(contractAddress);

        ContractData storage contractData = l.contractsData[contractAddress];
        contractData.contractAddress = contractAddress;
        contractData.mintFunctionSignature = mintFunctionSignature;
        contractData.contractType = contractType;
        contractData.isPriceUSD = isPriceUSD;

        uint256 i;
        uint256 length = payTiers.length;
        for (; i < length; ) {
            setPayTier(l, contractAddress, payTiers[i].tier, payTiers[i].price);

            unchecked {
                ++i;
            }
        }

        l.addresses.add(contractAddress);
    }

    function addDiscount(
        Layout storage l,
        address contractAddress,
        uint256 discount,
        uint256 discountExpiration,
        uint256 discountStartDate,
        uint256 avatarStartId,
        uint256 avatarEndId,
        uint256 seasonId
    ) internal {
        if (l.contractsData[contractAddress].contractAddress == address(0))
            revert ContractIdentifierDoesNotExist(contractAddress);

        uint256 i;
        uint256 length = l.seasonIdToDiscounts[seasonId].length;
        for (; i < length; ) {
            Discount storage existingDiscount = l.seasonIdToDiscounts[seasonId][
                i
            ];
            bool isTimeOverlapping = (discountStartDate <
                existingDiscount.discountExpiration) &&
                (discountExpiration > existingDiscount.discountStartDate);
            bool isTokenIdRangeOverlapping = !(avatarEndId <
                existingDiscount.avatarStartId ||
                avatarStartId > existingDiscount.avatarEndId);
            if (isTimeOverlapping && isTokenIdRangeOverlapping)
                revert InvalidOverlapInDiscounts(seasonId, i);
            unchecked {
                ++i;
            }
        }

        Discount storage newDiscount = l.seasonIdToDiscounts[seasonId].push();

        newDiscount.discount = discount;
        newDiscount.discountExpiration = discountExpiration;
        newDiscount.discountStartDate = discountStartDate;
        newDiscount.avatarStartId = avatarStartId;
        newDiscount.avatarEndId = avatarEndId;
    }

    function removeContract(
        Layout storage l,
        address contractAddress
    ) internal {
        if (!l.contains(contractAddress))
            revert IdentifierNotFound(contractAddress);
        l.removeContractData(contractAddress);
    }

    function updateContract(
        Layout storage l,
        address oldContractAddress,
        address newContractAddress,
        string calldata newFunctionSignature,
        ContractType newContractType,
        bool isPriceUSD,
        AddPayTier[] calldata payTiers
    ) internal {
        if (!l.contains(oldContractAddress)) {
            revert IdentifierNotFound(oldContractAddress);
        }

        l.removeContractData(oldContractAddress);

        ContractData storage contractData = l.contractsData[newContractAddress];
        contractData.contractAddress = newContractAddress;
        contractData.mintFunctionSignature = newFunctionSignature;
        contractData.contractType = newContractType;
        contractData.isPriceUSD = isPriceUSD;


        uint256 i;
        uint256 length = contractData.tiers.length();
        for (; i < length; ) {
            delete contractData.tierToPrice[contractData.tiers.at(i)];

            unchecked {
                ++i;
            }
        }

        uint256 j;
        uint256 payTiersLength = payTiers.length;
        for (; j < payTiersLength; ) {
            setPayTier(
                l,
                newContractAddress,
                payTiers[j].tier,
                payTiers[j].price
            );

            unchecked {
                ++j;
            }
        }
    }

    function getContract(
        Layout storage l,
        address contractAddress
    ) internal view returns (ContractData storage) {
        if (l.contractsData[contractAddress].contractAddress == address(0)) {
            revert ContractIdentifierDoesNotExist(contractAddress);
        }

        return l.contractsData[contractAddress];
    }

    function getAllIdentifiers(
        Layout storage l
    ) internal view returns (address[] memory) {
        uint256 i;
        uint256 addressesLength = l.addresses.length();
        address[] memory addresses = new address[](addressesLength);

        for (; i < addressesLength; ) {
            addresses[i] = l.addresses.at(i);
            unchecked {
                ++i;
            }
        }
        return addresses;
    }

    /**
     * @notice Returns the Price Feed address
     * @return priceFeed Price Feed address
     */
    function getPriceFeed(
        Layout storage l
    ) internal view returns (AggregatorV3Interface priceFeed) {
        priceFeed = AggregatorV3Interface(l.priceFeedAddress);

        return priceFeed;
    }

    /**
     * @notice Returns the latest price
     * @return latest price
     */
    function getLatestPrice(Layout storage l) internal view returns (uint256) {
        AggregatorV3Interface priceFeed = l.getPriceFeed();
        (, int256 price, , , ) = priceFeed.latestRoundData();

        return uint256(price);
    }

    // convertUSDtoWei
    function convertUSDtoWei(
        Layout storage l,
        uint256 _price
    ) internal view returns (uint256) {
        return (1e18 / (getLatestPrice(l) / 1e6)) * _price;
    }

    function setPayTier(
        Layout storage l,
        address _contractAddress,
        uint256 _tier,
        uint256 _price
    ) public {
        ContractData storage contractData = getContract(l, _contractAddress);

        if (contractData.tiers.contains(_tier)) {
            revert DuplicatePayTier(_tier);
        }

        contractData.tiers.add(_tier);
        contractData.tierToPrice[_tier] = _price;        
    }
}
